import boto3
import re

def is_valid_url(url):
    # Basic URL validation
    url_regex = re.compile(
        r'^(https:\/\/)'  # Ensure URL starts with https://
        r'([a-zA-Z0-9-]+\.)+[a-zA-Z]{2,6}'  # Domain
        r'(\/[a-zA-Z0-9-._~:\/?#\[\]@!$&\'()*+,;=]*)?$'  # Path
    )
    return re.match(url_regex, url) is not None

def subscribe_to_sns():
    sns_client = boto3.client('sns')
    topic_arn = 'arn:aws:sns:us-east-1:123456789012:MyTopic'  # Example ARN, replace with actual

    user_provided_url = input("Enter the subscription endpoint URL: ").strip()

    if not is_valid_url(user_provided_url):
        print("Invalid URL. Please provide a valid HTTPS URL.")
        return

    try:
        response = sns_client.subscribe(
            TopicArn=topic_arn,
            Protocol='https',
            Endpoint=user_provided_url
        )
        print("Subscription ARN:", response['SubscriptionArn'])
    except Exception as e:
        print("Error subscribing to SNS:", str(e))

if __name__ == "__main__":
    subscribe_to_sns()